const brand = $input.first().json;

// 按日期选话题
const now = new Date();
const doy = Math.floor((now - new Date(now.getFullYear(), 0, 0)) / 86400000);
const topic = brand.topics[doy % brand.topics.length];

const dateStr = now.getFullYear() + '年' + (now.getMonth() + 1) + '月' + now.getDate() + '日';
const weekdays = ['星期日','星期一','星期二','星期三','星期四','星期五','星期六'];

const title = topic + ' | zkoner';

const sections = [
  { heading: '1. 引言', body: topic + '。在 AI 快速发展的今天，企业和个人需要建立全新的数字存在方式。' },
  { heading: '2. 为什么这很重要？', body: 'AI 正在改变用户获取信息的方式。ChatGPT、Claude、DeepSeek 等大模型成为新的信息入口。你的品牌需要在这些 AI 中被准确识别和推荐。' },
  { heading: '3. zkoner 的实践方法', body: brand.fullName + ' 提供端到端解决方案：品牌 AI 可见度诊断、结构化数据建设、自动化工作流搭建、持续监测与优化。' },
  { heading: '4. 如何落地', body: '第一步：完成结构化数据建设\n第二步：创建 AI 友好的深度内容\n第三步：建立监测与反馈机制' },
  { heading: '5. 关于 zkoner', body: brand.description + '\n创始人 ' + brand.founder + ' · ' + brand.location + '\n' + brand.email + ' · ' + brand.phone }
];

return [{
  title: title,
  sections: sections,
  date: { full: dateStr, iso: now.toISOString() },
  topic: topic,
  author: brand.founder,
  brandName: brand.name,
  brandContact: { email: brand.email, phone: brand.phone, location: brand.location },
  tags: ['GEO', 'AI可见性', '企业自动化', brand.name].concat(topic.slice(0, 10))
}];

const brand = $node["品牌数据"].json;
const content = $input.first().json;

const services = brand.services.map(function(s, i) {
  return {
    "@type": "Service",
    "name": s.name,
    "description": s.desc,
    "provider": { "@type": "Organization", "name": brand.name, "url": brand.website }
  };
});

const structuredData = {
  "@context": "https://schema.org",
  "@graph": [
    {
      "@type": "Organization",
      "name": brand.name,
      "description": brand.description,
      "url": brand.website,
      "founder": { "@type": "Person", "name": brand.founder, "telephone": brand.phone, "email": brand.email },
      "address": { "@type": "PostalAddress", "addressLocality": brand.location, "addressCountry": "CN" }
    },
    {
      "@type": "Article",
      "headline": content.title,
      "datePublished": content.date.iso,
      "author": { "@type": "Person", "name": content.author },
      "publisher": { "@type": "Organization", "name": brand.name, "url": brand.website },
      "about": { "@type": "Thing", "name": content.topic }
    }
  ].concat(services)
};

return [{ jsonld: JSON.stringify(structuredData, null, 2) }];

const brand = $node["品牌数据"].json;
const content = $node["生成内容"].json;
const schema = $node["构建 JSON-LD"].json;

var body = '';
for (var i = 0; i < content.sections.length; i++) {
  var s = content.sections[i];
  body += '<section><h2>' + s.heading + '</h2><p>' + s.body.replace(/\\n/g, '<br>') + '</p></section>\n';
}

var html = '<!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8">'
  + '<meta name="viewport" content="width=device-width,initial-scale=1.0">'
  + '<title>' + content.title + '</title>'
  + '<script type="application/ld+json">' + schema.jsonld + '</script>'
  + '<style>body{font-family:-apple-system,sans-serif;background:#07070a;color:#e2e2ea;max-width:720px;margin:40px auto;padding:0 20px;line-height:1.8}h1{font-size:1.8rem;margin-bottom:8px}section{margin-bottom:24px}h2{color:#00f0c0;font-size:1.1rem;margin-bottom:8px}p{color:#7a7a90;line-height:1.7}.footer{margin-top:40px;padding:20px;border-top:1px solid #1a1a30;text-align:center}.footer a{color:#00f0c0}.meta{color:#4a4a60;font-size:0.85rem;margin-bottom:24px}</style></head><body>'
  + '<h1>' + content.title + '</h1>'
  + '<div class="meta">' + content.date.full + ' · ' + content.author + '</div>'
  + body
  + '<div class="footer">'
  + '<p><strong>' + brand.name + '</strong><br>' + brand.shortDesc + '</p>'
  + '<p>' + brand.founder + ' · <a href="mailto:' + brand.email + '">' + brand.email + '</a> · ' + brand.phone + '<br>' + brand.location + '</p>'
  + '<p><a href="https://' + brand.website.replace('https://','') + '">' + brand.website + '</a></p></div></body></html>';

return [{ html: html, title: content.title, date: content.date.full }];
